// Template guide sections generator — now with category-specific deep content
function generateGuideSections(name: string): GuideSection[] {
  const sub = subcategories[Object.keys(subcategories).find(k => subcategories[k].name === name) || ''];
  const parentCategory = sub?.parentCategory || 'Other';
  const hash = simpleHash(name);

  const templates = guideTemplatesByCategory[parentCategory] || guideTemplatesByCategory['Other'];
  const tpl = templates[hash % templates.length];

  return [
    { title: tpl.t1(name), subsections: tpl.s1(name) },
    { title: tpl.t2(name), subsections: tpl.s2(name) },
  ];
}


